using System;
using System.Diagnostics;
using SkiaSharp;

static long GetMemoryMb()
{
    GC.Collect();
    GC.WaitForPendingFinalizers();
    GC.Collect();
    return Process.GetCurrentProcess().WorkingSet64 / (1024 * 1024);
}

Console.WriteLine($"SkiaSharp: {typeof(SKBitmap).Assembly.GetName().Version}");
Console.WriteLine($"OS: {Environment.OSVersion}");

var baseline = GetMemoryMb();
long max = baseline;
for (var i = 0; i < 220; i++)
{
    using var bitmap = new SKBitmap(3840, 2160, SKColorType.Bgra8888, SKAlphaType.Premul);
    using var canvas = new SKCanvas(bitmap);
    canvas.Clear(SKColors.White);
    using var paint = new SKPaint { IsAntialias = true, Style = SKPaintStyle.Stroke, StrokeWidth = 2 };

    for (var j = 0; j < 600; j++)
    {
        paint.Color = new SKColor((byte)(j % 255), (byte)((j * 3) % 255), (byte)((j * 7) % 255));
        var y = (j * 7) % 2160;
        canvas.DrawLine(0, y, 3839, y, paint);
    }

    if ((i + 1) % 40 == 0)
    {
        var current = GetMemoryMb();
        if (current > max)
            max = current;
        Console.WriteLine($"Iteration {i + 1}: working-set={current}MB");
    }
}

var final = GetMemoryMb();
if (final > max)
    max = final;

Console.WriteLine($"BaselineMB={baseline}; FinalMB={final}; PeakMB={max}; GrowthMB={final - baseline}");
Console.WriteLine((final - baseline) > 200 ? "POTENTIAL_LEAK_PATTERN" : "NO_LEAK_PATTERN");
